#include <stdio.h>
#include <stdlib.h>
#define MOD 1000000007LL
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    int totalN=0; long long maxA=0;
    // store inputs temporarily
    int *Ns = (int*)malloc(T*sizeof(int));
    int **arr = (int**)malloc(T*sizeof(int*));
    for(int t=0;t<T;++t){
        int N; scanf("%d", &N); Ns[t]=N; totalN+=N;
        arr[t]=(int*)malloc(N*sizeof(int));
        for(int i=0;i<N;++i){
            int x; scanf("%d", &x); arr[t][i]=x; if(x>maxA) maxA=x;
        }
    }
    // precompute factorials up to maxA
    long long *fact = (long long*)malloc((maxA+1)*sizeof(long long));
    fact[0]=1;
    for(long long i=1;i<=maxA;++i) fact[i]=(fact[i-1]*i)%MOD;
    // answer each test case
    for(int t=0;t<T;++t){
        long long sum=0;
        for(int i=0;i<Ns[t];++i){
            sum += fact[arr[t][i]];
            if(sum>=MOD) sum-=MOD;
        }
        printf("%lld\n", sum%MOD);
        free(arr[t]);
    }
    free(arr); free(Ns); free(fact);
    return 0;
}

