            cin>>all[t][i];
            maxA = max(maxA, all[t][i]);
        }
    }
    vector<long long> fact(maxA+1);
    fact[0]=1;
    for(int i=1;i<=maxA;++i) fact[i]=fact[i-1]*i%MOD;
    for(int t=0;t<T;++t){
        long long ans=0;
        for(int x: all[t]){
            ans += fact[x];
            if(ans>=MOD) ans-=MOD;
        }
        cout<<ans%MOD<<"\n";
    }
    return 0;
}

