import java.io.*;
import java.util.*;
public class Main {
    static final long MOD = 1_000_000_007L;
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        int[] Ns = new int[T];
        List<int[]> all = new ArrayList<>(T);
        int maxA = 0;
        for (int t = 0; t < T; t++) {
            int N = fs.nextInt();
            Ns[t] = N;
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) {
                arr[i] = fs.nextInt();
                if (arr[i] > maxA) maxA = arr[i];
            }
            all.add(arr);
        }
        long[] fact = new long[maxA + 1];
        fact[0] = 1;
        for (int i = 1; i <= maxA; i++) fact[i] = (fact[i - 1] * i) % MOD;
        StringBuilder sb = new StringBuilder();
        for (int t = 0; t < T; t++) {
            long sum = 0;
            for (int x : all.get(t)) {
                sum += fact[x];
                if (sum >= MOD) sum -= MOD;
            }
            sb.append(sum % MOD).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for speed
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

