const fs = require('fs');
const MOD = 1000000007n;
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(BigInt);
let idx = 0n;
if (input.length === 0) process.exit(0);
const T = Number(input[idx++]);
let testCases = [];
let maxA = 0n;
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  const arr = [];
  for (let i = 0; i < N; i++) {
    const val = input[idx++];
    arr.push(Number(val));
    if (val > maxA) maxA = val;
  }
  testCases.push(arr);
}
const max = Number(maxA);
const fact = new Array(max + 1);
fact[0] = 1n;
for (let i = 1; i <= max; i++) {
  fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
}
let output = [];
for (const arr of testCases) {
  let sum = 0n;
  for (const v of arr) {
    sum += fact[v];
    if (sum >= MOD) sum -= MOD;
  }
  output.push((sum % MOD).toString());
}
console.log(output.join('\n'));
